private void FixedUpdate()&#123;    //刚体移动    //rigid.position += planarVec * Time.fixedDeltaTime;    rigid.position += deltaPos;//加上rootmotion的移动    rigid.velocity = new Vector3(planarVec.x, rigid.velocity.y, planarVec.z) + thrustVec;    thrustVec = Vector3.zero;//突发力清零    deltaPos = Vector3.zero;//rootmotion的移动量清零&#125;

