/// &lt;summary&gt;/// 清空累计Trigger/// &lt;/summary&gt;public class FSMClearSignals : StateMachineBehaviour&#123;    public string[] ClearAtEnter;    public string[] ClearAtExit;    override public void OnStateEnter(Animator animator, AnimatorStateInfo stateInfo, int layerIndex)    &#123;        //进入时清空trigger        foreach (var item in ClearAtEnter)        &#123;            animator.ResetTrigger(item);        &#125;    &#125;    override public void OnStateExit(Animator animator, AnimatorStateInfo stateInfo, int layerIndex)    &#123;        //退出时清空trigger        foreach (var item in ClearAtExit)        &#123;            animator.ResetTrigger(item);        &#125;    &#125;&#125;

FSMOnEnter
/// &lt;summary&gt;/// 动画进入时调用/// TODO:浪费资源的做法  animator.gameObject.SendMessageUpwards(message);/// &lt;/summary&gt;public class FSMOnEnter : StateMachineBehaviour&#123;    public string[] OnEnterMessage;    //发送消息给播放动画的游戏对象 调用OnEnterMessage里名字的函数    override public void OnStateEnter(Animator animator, AnimatorStateInfo stateInfo, int layerIndex)    &#123;        foreach (var message in OnEnterMessage)        &#123;            animator.gameObject.SendMessageUpwards(message);        &#125;    &#125;&#125;

FSMOnExit
