这个命令模式确实有点意思,可以将判断与执行解耦,并且可以回退,原因是Commmad记录了操作对象执行命令之前的状态,或者Revock可以给到一个相反的状态
并且文中提到如果使用第一公民函数的语言和闭包也可以实现,重点就是要可以记录状态。
public interface BaseCommand&#123;    /// &lt;summary&gt;    /// 执行命令    /// &lt;/summary&gt;    /// &lt;param name=&quot;command&quot;&gt;&lt;/param&gt;    /// &lt;param name=&quot;obj&quot;&gt;&lt;/param&gt;    public void Execute(GameObject gameObject);    /// &lt;summary&gt;    /// 回退命令    /// &lt;/summary&gt;    /// &lt;param name=&quot;obj&quot;&gt;&lt;/param&gt;    public void Revoke(GameObject gameObject);&#125;public class MoveCommand : BaseCommand&#123;    private GameObject m_gameObject;    private Vector3 m_direction;    public MoveCommand(Vector3 dir)    &#123;        m_direction = dir;    &#125;    public void Execute(GameObject obj)    &#123;        m_gameObject = obj;        m_gameObject.transform.Translate(m_direction);    &#125;    public void Revoke(GameObject obj)    &#123;        m_gameObject = obj;        m_gameObject.transform.Translate(Quaternion.Euler(0f, 180f, 0f) * m_direction);    &#125;&#125;public static class CommandManager&#123;    private static Stack&lt;BaseCommand&gt; m_commands = new Stack&lt;BaseCommand&gt;();    public static void Clear() &#123; m_commands.Clear(); &#125;    /// &lt;summary&gt;    /// 执行命令    /// &lt;/summary&gt;    /// &lt;param name=&quot;command&quot;&gt;&lt;/param&gt;    /// &lt;param name=&quot;obj&quot;&gt;&lt;/param&gt;    public static void Excute(BaseCommand command, GameObject obj)    &#123;        command.Execute(obj);        m_commands.Push(command);    &#125;    /// &lt;summary&gt;    /// 回退命令    /// &lt;/summary&gt;    /// &lt;param name=&quot;obj&quot;&gt;&lt;/param&gt;    public static void Revock(GameObject obj)    &#123;        if (m_commands.TryPop(out BaseCommand commmand))        &#123;            commmand.Revoke(obj);        &#125;    &#125;&#125;public class TestCommandMode : MonoBehaviour&#123;    private MoveCommand m_moveForwad;    private MoveCommand m_moveBack;    private MoveCommand m_moveLeft;    private MoveCommand m_moveRight;    private void Start()    &#123;        m_moveForwad = new MoveCommand(Vector3.forward);        m_moveBack = new MoveCommand(Vector3.back);        m_moveLeft = new MoveCommand(Vector3.left);        m_moveRight = new MoveCommand(Vector3.right);    &#125;    private void Update()    &#123;        if (Input.GetKeyDown(KeyCode.W))        &#123;            CommandManager.Excute(m_moveForwad, gameObject);        &#125;        if (Input.GetKeyDown(KeyCode.S))        &#123;            CommandManager.Excute(m_moveBack, gameObject);        &#125;        if (Input.GetKeyDown(KeyCode.A))        &#123;            CommandManager.Excute(m_moveLeft, gameObject);        &#125;        if (Input.GetKeyDown(KeyCode.D))        &#123;            CommandManager.Excute(m_moveRight, gameObject);        &#125;        if (Input.GetKeyDown(KeyCode.R))        &#123;            CommandManager.Revock(gameObject);        &#125;    &#125;&#125;

1.1 函数的头文件编写​	在C++中，我们在C++的头文件中声明 类、变量、函数。就可以在其他地方用include的头文件，然后再做定义。
作用：让代码结构更加清晰
函数分文件编写一般有4个步骤

创建后缀名为.h的头文件  
创建后缀名为.cpp的源文件
在头文件中写函数的声明
在源文件中写函数的定义

示例：
//swap.h文件#include&lt;iostream&gt;using namespace std;//实现两个数字交换的函数声明void swap(int a, int b);

//swap.cpp文件#include &quot;swap.h&quot;void swap(int a, int b)&#123;	int temp = a;	a = b;	b = temp;	cout &lt;&lt; &quot;a = &quot; &lt;&lt; a &lt;&lt; endl;	cout &lt;&lt; &quot;b = &quot; &lt;&lt; b &lt;&lt; endl;&#125;

//main函数文件#include &quot;swap.h&quot;int main() &#123;	int a = 100;	int b = 200;	swap(a, b);	system(&quot;pause&quot;);	return 0;&#125;

2.1 指针所占内存空间​	提问：指针也是种数据类型，那么这种数据类型占用多少内存空间？
​	在C++中，一个指针所占的字节数由操作系统的位数决定。一个指向int类型的指针，在32位操作系统中是4个字节在64位操作系统中是8个字节。
示例：
int main() &#123;	int a = 10;	int * p;	p = &amp;a; //指针指向数据a的地址	cout &lt;&lt; *p &lt;&lt; endl; //* 解引用	cout &lt;&lt; sizeof(p) &lt;&lt; endl;	cout &lt;&lt; sizeof(char *) &lt;&lt; endl;	cout &lt;&lt; sizeof(float *) &lt;&lt; endl;	cout &lt;&lt; sizeof(double *) &lt;&lt; endl;	system(&quot;pause&quot;);	return 0;&#125;


总结：所有指针类型在32位操作系统下是4个字节

2.2 指针的定义形式​	此外 int *a 和int* a  是同没有差别的，只是写法上的不同。同理，当我们使用int数组作为形参时 int a[] 和 int* a也没有区别，都是传递指针。
​	补： 作为形参时， int a[] 和 int* a还是有区别的，int a[] 是常量，int* a是变量
int *a ;int* a ;int * a;

void(int a[])&#123;&#125;void(int* a)&#123;&#125;



2.3 const修饰指针const修饰指针有三种情况

const修饰指针   — 常量指针
const修饰常量   — 指针常量
const即修饰指针，又修饰常量

示例：
int main() &#123;	int a = 10;	int b = 10;	//const修饰的是指针，指针指向可以改，指针指向的值不可以更改	const int * p1 = &amp;a; 	p1 = &amp;b; //正确	//*p1 = 100;  报错		//const修饰的是常量，指针指向不可以改，指针指向的值可以更改	int * const p2 = &amp;a;	//p2 = &amp;b; //错误	*p2 = 100; //正确    //const既修饰指针又修饰常量	const int * const p3 = &amp;a;	//p3 = &amp;b; //错误	//*p3 = 100; //错误	system(&quot;pause&quot;);	return 0;&#125;




技巧：看const右侧紧跟着的是指针还是常量, 是指针就是常量指针，是常量就是指针常量 ，简而言之 const修饰谁 谁就不可以更改

2.4 空指针和野指针空指针：指针变量指向内存中编号为0的空间
用途：初始化指针变量
注意：空指针指向的内存是不可以访问的
示例1：空指针
int main() &#123;	//指针变量p指向内存地址编号为0的空间	int * p = NULL;	//访问空指针报错 	//内存编号0 ~255为系统占用内存，不允许用户访问	cout &lt;&lt; *p &lt;&lt; endl;	system(&quot;pause&quot;);	return 0;&#125;



野指针：指针变量指向非法的内存空间
示例2：野指针
int main() &#123;	//指针变量p指向内存地址编号为0x1100的空间	int * p = (int *)0x1100;	//访问野指针报错 	cout &lt;&lt; *p &lt;&lt; endl;	system(&quot;pause&quot;);	return 0;&#125;




总结：空指针和野指针都不是我们申请的空间，因此不要访问。

2.5 指针、数组、函数案例描述：封装一个函数，利用冒泡排序，实现对整型数组的升序排序
例如数组：int arr[10] &#x3D; { 4,3,6,9,1,2,10,8,7,5 };
示例：
//冒泡排序函数void bubbleSort(int * arr, int len)  //int * arr 也可以写为int arr[]&#123;	for (int i = 0; i &lt; len - 1; i++)	&#123;		for (int j = 0; j &lt; len - 1 - i; j++)		&#123;			if (arr[j] &gt; arr[j + 1])			&#123;				int temp = arr[j];				arr[j] = arr[j + 1];				arr[j + 1] = temp;			&#125;		&#125;	&#125;&#125;//打印数组函数void printArray(int arr[], int len)&#123;	for (int i = 0; i &lt; len; i++)	&#123;		cout &lt;&lt; arr[i] &lt;&lt; endl;	&#125;&#125;int main() &#123;	int arr[10] = &#123; 4,3,6,9,1,2,10,8,7,5 &#125;;	int len = sizeof(arr) / sizeof(int);	bubbleSort(arr, len);	printArray(arr, len);	system(&quot;pause&quot;);	return 0;&#125;




总结：当数组名传入到函数作为参数时，被退化为指向首元素的指针

2.6 删除数组空间用new在堆区空间开辟的数据如果是数组的话，需要delete[]
示例：
