L3文件流#region 1.打开或创建指定文件//方法-：new Filestream//参数一：路径//参数二：打开模式//CreateNew:    创建新文件如果文件存在则报错//Create:       创建文件，如果文件存在则覆盖//Open:         打开文件，如果文件不存在报错//OpenorCreate: 打开或者创建文件根据实际情况操作//Append:       若存在文件，则打开并查找文件尾，或者创建一个新文件//Truncate:     打开并清空文件内容//参数三： 访问模式//参数四： 共享权限//None      谢绝共享//Read      允许别的程序读取当前文件//Write     允许别的程序写入该文件//ReadWrite 允许别的程序读写该文件FileStream fs = new FileStream(PeresistentURL(&quot;TestNew.Test&quot;), FileMode.OpenOrCreate, FileAccess.ReadWrite);//方法三：Fi1e.0pen//参数一：路径//参数二：打开模式FileStream fs1 = File.Open(PeresistentURL(&quot;TestNew1.Test&quot;), FileMode.Open);fs1.Close();fs1.Dispose();//方法二:File.Create//参数一路径//参数二：缓存大小//参数三：描述如何创建或覆盖该文件（不常用）//Asynchronous 可用于异步读写//DeleteOnclose 不在使用时，自动删除//Encrypted 加密//None 不应用其它选项//RandomAccess 随机访问文件//Sequentialscan 从头到尾顺序访问文件//WriteThrough 通过中间缓存直接写入磁盘FileStream fs2 = File.Create(PeresistentURL(&quot;TestNew1.Test&quot;), 2048);fs2.Close();fs2.Dispose();#endregion#region 2.属性方法//1. 是否可写if (fs.CanRead) &#123; &#125;//2.是否可读if (fs.CanWrite) &#123; &#125;//3.将字节写入文件当写入后一定执行一次fs.Flush();//4.关闭流当文件读写完毕后一定执行fs.Close();//5.缓存资源销毁回收fs.Dispose();#endregion#region 3.写入字节//方法：Write//参数一：写入的字节数组//参数二：数组中的开始索引//参数三：写入多少个字节using (fs = new FileStream(PeresistentURL(&quot;TestNew.Test&quot;), FileMode.OpenOrCreate, FileAccess.ReadWrite))&#123;    byte[] bytes = BitConverter.GetBytes(1 &lt;&lt; 8);    fs.Write(bytes, 0, bytes.Length);    //写入字符串时    bytes = Encoding.UTF8.GetBytes(&quot;hello world&quot;);    //先写入长度    byte[] length = BitConverter.GetBytes(bytes.Length);    fs.Write(length, 0, length.Length);    //再写入字符串具体内容    fs.Write(bytes, 0, bytes.Length);    fs.Flush();//3.将字节写入文件当写入后一定执行一次    fs.Close(); //5.缓存资源销毁回收&#125;;#endregion#region 4.读取字节//方法一using (fs = File.Open(PeresistentURL(&quot;TestNew.Test&quot;), FileMode.Open, FileAccess.Read))&#123;    //参数一：用于存储读取的字节数组的容器    //参数二：容器中开始的位置    //参数三：读取多少个字节装入容器    //返回值：当前流索引前进了几个位置    byte[] bytes2 = new byte[4];    int index = fs.Read(bytes2, 0, 4);    int i = BitConverter.ToInt32(bytes2, 0);    print(&quot;取出来的第一个整数&quot; + i);//999    print(&quot;索引向前移动&quot; + index + &quot;个位置&quot;);    //读取第二个字符串    //读取字符串字节数组长度    index = fs.Read(bytes2, 0, 4);    print(&quot;索引向前移动&quot; + index + &quot;个位置&quot;);    int length1 = BitConverter.ToInt32(bytes2, 0);    bytes2 = new byte[length1];    index = fs.Read(bytes2, 0, length1);    print(&quot;索引向前移动&quot; + index + &quot;个位置&quot;);    //得到最终的字符串打印出来    print(Encoding.UTF8.GetString(bytes2));    fs.Flush();    fs.Close();&#125;//方法二 一次性读取长度using (fs = File.Open(PeresistentURL(&quot;/TestNew.Test&quot;), FileMode.Open))&#123;    print(&quot;=============================&quot;);    //一开始就申明一个和文件字节数组长度一样的容器     byte[] bytes3 = new byte[fs.Length];    fs.Read(bytes3, 0, bytes3.Length);    fs.Dispose();    //读取整数    print(BitConverter.ToInt32(bytes3, 0));    //读取字符串字节数组的长度    int length2 = BitConverter.ToInt32(bytes3, 4);    //得到字符串    print(Encoding.UTF8.GetString(bytes3, 8, length2));&#125;#endregion#region 知识点三更加安全的使用文件流对象//using 关键字重要用法//using (申明一个引用对象) I//使用对象//无论发生什么情况当 using 语句块结束后会自动调用该对象的销毁方法避免忘记销毁或关闭流//using 是一种更安全的使用方法/强调：//目前我们对文件流进行操作为了文件操作安全都用 using 来进行处理最好#endregion        private String AssetURL(string url)&#123;    return Application.dataPath + &quot;/&quot; + url;&#125;private String PeresistentURL(string url)&#123;    print(Application.persistentDataPath + &quot;/&quot; + url);    return Application.persistentDataPath + &quot;/&quot; + url;&#125;

