Action&lt;T&gt;是unity为我们包装的泛型委托
namespace System&#123;    public delegate void Action&lt;in T&gt;(T obj);&#125;

委托可以看成一个函数类型 传入的泛型T就是函数参数的类型

事件 就是 一个委托列表 本质也是一个委托
所以事件可以  事件+&#x3D;委托


using System;using System.Collections.Generic;using Unity.VisualScripting.Dependencies.NCalc;public class EVENTNAME&#123;    public const string PLAYER_DIE = &quot;PLAYER_DIE&quot;;&#125;public class EventCenter : BaseManager&lt;EventCenter&gt;&#123;    //储存事件的字典    Dictionary&lt;string, Action&lt;object&gt;&gt; eventDic = new Dictionary&lt;string, Action&lt;object&gt;&gt;();    /// &lt;summary&gt;    /// 添加事件监听的方法    /// &lt;/summary&gt;    /// &lt;param name=&quot;name&quot;&gt;&lt;/param&gt;    /// &lt;param name=&quot;action&quot;&gt;&lt;/param&gt;    public void AddEventListener(string name, Action&lt;object&gt; action)    &#123;        //如果有这个事件        //添加这个函数(委托)到事件里        //事件 就是 一个委托列表 本质也是一个委托        if (eventDic.ContainsKey(name))        &#123;            eventDic[name] += action;        &#125;        //没有这个事件 就把这个委托作为事件也就创建了一个事件        else        &#123;            eventDic.Add(name, action);        &#125;    &#125;    /// &lt;summary&gt;    /// 移除事件监听的方法    /// &lt;/summary&gt;    /// &lt;param name=&quot;name&quot;&gt;&lt;/param&gt;    /// &lt;param name=&quot;action&quot;&gt;&lt;/param&gt;    public void RemoveEventListener(string name, Action&lt;object&gt; action)    &#123;        if (eventDic.ContainsKey(name))        &#123;            eventDic[name] -= action;        &#125;    &#125;    /// &lt;summary&gt;    /// 触发事件的方法    /// &lt;/summary&gt;    /// &lt;param name=&quot;name&quot;&gt;&lt;/param&gt;    /// &lt;param name=&quot;info&quot;&gt;&lt;/param&gt;    public void TriggerEvent(string name, object info)    &#123;        if (eventDic.ContainsKey(name))        &#123;            eventDic[name].Invoke(info);        &#125;    &#125;    /// &lt;summary&gt;    /// 当场景转换时清空所有事件    /// &lt;/summary&gt;    public void Clear()    &#123;        eventDic.Clear();    &#125;&#125;

