 public class InputMgr : BaseManager&lt;InputMgr&gt;&#123;    //开启或关闭按键监听    private bool isStart = false;    //在构造函数里添加UpdateEvent事件监听    //因为这不是继承mono的类    public InputMgr()    &#123;        MonoMgr.GetInstance().controller.AddUpdateEventListener(MyUpdate);    &#125;    /// &lt;summary&gt;    /// 开启或关闭按键监听    /// &lt;/summary&gt;    /// &lt;param name=&quot;flag&quot;&gt;true: start,fasle: end&lt;/param&gt;    public void StartOrEndCheck(bool flag)    &#123;        isStart = flag;    &#125;    //按键监听    //监听到了就让事件中心分发一个事件    //让关心此事件的监听即可    private void CheckKey(KeyCode key)    &#123;        if (Input.GetKeyDown(key))            EventCenter.GetInstance().TriggerEvent&lt;KeyCode&gt;(&quot;按键按下&quot;, key);        if (Input.GetKeyUp(key))            EventCenter.GetInstance().TriggerEvent&lt;KeyCode&gt;(&quot;按键抬起&quot;, key);    &#125;    //帧更新调用    //如果按键监听关闭则return    private void MyUpdate()    &#123;        if (!isStart) return;        CheckKey(KeyCode.W);        CheckKey(KeyCode.A);        CheckKey(KeyCode.S);        CheckKey(KeyCode.D);    &#125;&#125;

之前事件中心的回调函数参数是object 有装箱拆箱问题 现在改为泛型
这里 EventInfo类中 不加event修饰符的原因是 加event只能内部调用这个事件 而事件中心是需要外部触发事件的 所有不加event

using System;using System.Collections.Generic;using Unity.VisualScripting.Dependencies.NCalc;public class EVENTNAME&#123;    public const string PLAYER_DIE = &quot;PLAYER_DIE&quot;;    public const string LOAD_SCENE_ING = &quot;LOAD_SCENE_DONE&quot;;&#125;//空接口public interface IEventInfo&#123;&#125;//IEventInfo 的子类 使得IEventInfo 成为一个中转站//这样我们就不用在Dictionary里放泛型了public class EventInfo&lt;T&gt; : IEventInfo&#123;    //这里不加event修饰符的原因是    //加event只能内部调用这个事件 而事件中心是需要外部触发事件的    //所有不加event    public Action&lt;T&gt; action;    public EventInfo(Action&lt;T&gt; action)    &#123;        this.action += action;    &#125;&#125;public class EventInfo : IEventInfo&#123;    public Action action;    public EventInfo(Action action)    &#123;        this.action += action;    &#125;&#125;/// &lt;summary&gt;/// 事件中心/// 储存事件并提供外部添加移除和触发事件/// 优化事件中心避免装箱拆箱/// &lt;/summary&gt;public class EventCenter : BaseManager&lt;EventCenter&gt;&#123;    //储存事件的字典    //Action&lt;object&gt; 改为储存他的接口父类    //Dictionary&lt;string, Action&lt;object&gt;&gt; eventDic = new Dictionary&lt;string, Action&lt;object&gt;&gt;();    Dictionary&lt;string, IEventInfo&gt; eventDic = new Dictionary&lt;string, IEventInfo&gt;();    /// &lt;summary&gt;    /// 添加事件监听的方法    /// &lt;/summary&gt;    /// &lt;param name=&quot;name&quot;&gt;&lt;/param&gt;    /// &lt;param name=&quot;action&quot;&gt;&lt;/param&gt;    public void AddEventListener&lt;T&gt;(string name, Action&lt;T&gt; action)    &#123;        //如果有这个事件        //添加这个函数(委托)到事件里        //事件 就是 一个委托列表 本质也是一个委托        if (eventDic.ContainsKey(name))        &#123;            //里氏转换 得到子类            (eventDic[name] as EventInfo&lt;T&gt;).action += action;        &#125;        //没有这个事件 就把这个委托作为事件也就创建了一个事件        else        &#123;            //在构造函数里初始化的到第一个action            //里氏转换 父类装子类            eventDic.Add(name, new EventInfo&lt;T&gt;(action));        &#125;    &#125;    /// &lt;summary&gt;    /// 无参添加事件监听的方法    /// &lt;/summary&gt;    /// &lt;param name=&quot;name&quot;&gt;&lt;/param&gt;    /// &lt;param name=&quot;action&quot;&gt;&lt;/param&gt;    public void AddEventListener(string name, Action action)    &#123;        //如果有这个事件        //添加这个函数(委托)到事件里        //事件 就是 一个委托列表 本质也是一个委托        if (eventDic.ContainsKey(name))        &#123;            //里氏转换 得到子类            (eventDic[name] as EventInfo).action += action;        &#125;        //没有这个事件 就把这个委托作为事件也就创建了一个事件        else        &#123;            //在构造函数里初始化的到第一个action            //里氏转换 父类装子类            eventDic.Add(name, new EventInfo(action));        &#125;    &#125;    /// &lt;summary&gt;    /// 移除事件监听的方法    /// &lt;/summary&gt;    /// &lt;param name=&quot;name&quot;&gt;&lt;/param&gt;    /// &lt;param name=&quot;action&quot;&gt;&lt;/param&gt;    public void RemoveEventListener&lt;T&gt;(string name, Action&lt;T&gt; action)    &#123;        if (eventDic.ContainsKey(name))        &#123;            //里氏转换 得到子类            (eventDic[name] as EventInfo&lt;T&gt;).action -= action;        &#125;    &#125;    /// &lt;summary&gt;    /// 无参移除事件监听的方法    /// &lt;/summary&gt;    /// &lt;param name=&quot;name&quot;&gt;&lt;/param&gt;    /// &lt;param name=&quot;action&quot;&gt;&lt;/param&gt;    public void RemoveEventListener(string name, Action action)    &#123;        if (eventDic.ContainsKey(name))        &#123;            //里氏转换 得到子类            (eventDic[name] as EventInfo).action -= action;        &#125;    &#125;    /// &lt;summary&gt;    /// 触发事件的方法    /// &lt;/summary&gt;    /// &lt;param name=&quot;name&quot;&gt;&lt;/param&gt;    /// &lt;param name=&quot;info&quot;&gt;&lt;/param&gt;    public void TriggerEvent&lt;T&gt;(string name, T info)    &#123;        if (eventDic.ContainsKey(name))        &#123;            //?判空            (eventDic[name] as EventInfo&lt;T&gt;).action?.Invoke(info);        &#125;    &#125;    /// &lt;summary&gt;    /// 无参触发事件的方法    /// &lt;/summary&gt;    /// &lt;param name=&quot;name&quot;&gt;&lt;/param&gt;    /// &lt;param name=&quot;info&quot;&gt;&lt;/param&gt;    public void TriggerEvent(string name)    &#123;        if (eventDic.ContainsKey(name))        &#123;            //?判空            (eventDic[name] as EventInfo).action?.Invoke();        &#125;    &#125;    /// &lt;summary&gt;    /// 当场景转换时清空所有事件    /// &lt;/summary&gt;    public void Clear()    &#123;        eventDic.Clear();    &#125;&#125;

