//application to vertex struct a2v&#123;    float4 vertex:POSITION; //告诉unity把模型空间下的顶点坐标填充给ventex     float3 normal:NORMAL; //告诉unity吧模型空间下的法线方向填充给norma1    float4 texcoord:TEXCOORD0; //告诉unity把第一套纹理坐标填充给texcoord&#125;;//vertex to fragmentstruct v2f&#123;    float4 position: SV_POSITION;    float3 temp: COLOR0;&#125;;//储存到vertex的color//顶点三角区域中的像素通过插值取到颜色v2f vert(a2v v)&#123;    v2f f;    f.position = UnityObjectToClipPos(v.vertex);    f.temp = v.normal;    return f;&#125;;fixed4 frag(v2f f) : SV_Target&#123;    return fixed4(f.temp, 1);&#125;;

兰伯特光照模型

公式 DiffuseColor = 直射光颜色 * max（0，cos（光和法线的夹角））;



半兰伯特关照模型

公式 DiffuseColor &#x3D; 直射光颜色 * ( 0.5 * cos(光和法线的夹角) + 0.5)

1)顶点漫反射Pass&#123;    CGPROGRAM    #pragma vertex vert    #pragma fragment frag    #include &quot;Lighting.cginc&quot;    //获得第一个直线光的颜色 _LightColor0    //_WorldSpaceLight 世界灯光    struct a2v    &#123;        float4 vertex : POSITION;        float3 normal: NORMAL;    &#125;;    struct v2f    &#123;        float4 vertex : SV_POSITION;        float3 normalColor: COLOR;    &#125;;    v2f vert(a2v v)    &#123;        v2f f;        f.vertex = UnityObjectToClipPos(v.vertex); //顶点localPos转换到裁剪Pos        //unity_WorldToObject 世界坐标转localPos矩阵 mul(unity_WorldToObject,obj),反过来lcoalPos转世界坐标        fixed3 normalDir = normalize(mul(v.normal, (float3x3)unity_WorldToObject));//法线坐标转换到世界坐标 再进行归一化         fixed3 lightDir = normalize(_WorldSpaceLightPos0.xyz);//_WorldSpaceLightPos0.xyz 灯光方向        fixed3 diffuse = _LightColor0.rgb * max(dot(normalDir, lightDir), 0);//灯光颜色 * max((灯光方向与 模型法线方向的点积),0); 得到漫反射颜色        f.normalColor = diffuse;//储存到v2f中        return f;    &#125;    fixed4 frag(v2f i) : SV_Target    &#123;        return fixed4(i.normalColor, 1);//拿到漫反射颜色    &#125;    ENDCG&#125;

高光反射公式： 

SpecularColor= 直射光颜色 * pow（max（dot(光线反射方向,摄象机方向)），0），高光参数）

